import{_ as e,o as l,c as r,ak as t}from"./chunks/framework.Chu_0La1.js";const b=JSON.parse('{"title":"🌸 SakuraBOT 专项功能","description":"","frontmatter":{"outline":[2,3]},"headers":[],"relativePath":"help/sakura/index.md","filePath":"doc/help/sakura/index.md"}'),s={name:"help/sakura/index.md"};function i(n,a,d,h,o,c){return l(),r("div",null,[...a[0]||(a[0]=[t(`<h1 id="🌸-sakurabot-专项功能" tabindex="-1">🌸 SakuraBOT 专项功能 <a class="header-anchor" href="#🌸-sakurabot-专项功能" aria-label="Permalink to “🌸 SakuraBOT 专项功能”">​</a></h1><div class="section-header" style="background:linear-gradient(135deg, #ffecd2 0%, #fcb69f 100%);"><p>专为《世界计划 多彩舞台》(Project SEKAI) 玩家打造的高级查询功能</p></div><div class="important custom-block github-alert"><p class="custom-block-title">使用须知</p><p></p><ul><li>运行以下 SakuraBOT 指令时，<strong>不需要</strong>添加 <code>@mzkbot</code> 前缀，直接发送指令即可</li><li>🌏 <strong>多服支持</strong>：涉及用户数据的指令，可添加 <code>tw</code> 或 <code>cn</code> 前缀来触发台服/国服专属功能（默认为日服）</li></ul></div><hr><h2 id="功能模块" tabindex="-1">功能模块 <a class="header-anchor" href="#功能模块" aria-label="Permalink to “功能模块”">​</a></h2><div class="module-grid"><h3 id="📊-用户数据管理" tabindex="-1">📊 <a href="./user-data">用户数据管理</a> <a class="header-anchor" href="#📊-用户数据管理" aria-label="Permalink to “📊 用户数据管理”">​</a></h3><p>绑定游戏账号、管理查询权限、查看基础信息</p><ul><li>绑定/解绑游戏 ID</li><li>设置查询权限</li><li>查看个人资料</li></ul><h3 id="📈-高阶数据分析" tabindex="-1">📈 <a href="./advanced">高阶数据分析</a> <a class="header-anchor" href="#📈-高阶数据分析" aria-label="Permalink to “📈 高阶数据分析”">​</a></h3><p>需要上传数据的高级查询功能</p><ul><li>排位信息查询</li><li>B30/B39 分析</li><li>歌曲完成进度</li></ul><h3 id="🃏-智能卡组推荐" tabindex="-1">🃏 <a href="./deck">智能卡组推荐</a> <a class="header-anchor" href="#🃏-智能卡组推荐" aria-label="Permalink to “🃏 智能卡组推荐”">​</a></h3><p>基于你的卡牌数据推荐最优卡组</p><ul><li>活动组卡</li><li>挑战组卡</li><li>最强卡组</li></ul><h3 id="🔍-查询与工具箱" tabindex="-1">🔍 <a href="./tools">查询与工具箱</a> <a class="header-anchor" href="#🔍-查询与工具箱" aria-label="Permalink to “🔍 查询与工具箱”">​</a></h3><p>无需上传数据即可使用的查询工具</p><ul><li>活动与排名查询</li><li>歌曲与谱面信息</li><li>卡牌查询</li><li>小游戏</li></ul></div><hr><h2 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to “快速开始”">​</a></h2><h3 id="第一步-绑定账号" tabindex="-1">第一步：绑定账号 <a class="header-anchor" href="#第一步-绑定账号" aria-label="Permalink to “第一步：绑定账号”">​</a></h3><p>使用 <a href="./user-data"><code>绑定 ID</code></a> 指令将你的游戏账号与 QQ 绑定</p><h3 id="第二步-设置权限" tabindex="-1">第二步：设置权限 <a class="header-anchor" href="#第二步-设置权限" aria-label="Permalink to “第二步：设置权限”">​</a></h3><p>使用 <a href="./user-data"><code>给看</code></a> 或 <a href="./user-data"><code>不给看</code></a> 设置他人是否可以查询你的数据</p><h3 id="第三步-上传数据-可选" tabindex="-1">第三步：上传数据（可选） <a class="header-anchor" href="#第三步-上传数据-可选" aria-label="Permalink to “第三步：上传数据（可选）”">​</a></h3><p>如需使用高阶功能，请访问 <a href="http://go.mikuware.top/" target="_blank" rel="noreferrer">数据上传页面</a></p><h3 id="第四步-开始使用" tabindex="-1">第四步：开始使用 <a class="header-anchor" href="#第四步-开始使用" aria-label="Permalink to “第四步：开始使用”">​</a></h3><p>根据需求选择相应的功能模块进行查询</p><hr><h2 id="服务器支持" tabindex="-1">服务器支持 <a class="header-anchor" href="#服务器支持" aria-label="Permalink to “服务器支持”">​</a></h2><table tabindex="0"><thead><tr><th>服务器</th><th>前缀</th><th>支持状态</th></tr></thead><tbody><tr><td>日服</td><td>默认</td><td>✅ 完全支持</td></tr><tr><td>台服</td><td><code>tw</code></td><td>✅ 支持</td></tr><tr><td>国服</td><td><code>cn</code></td><td>✅ 支持</td></tr></tbody></table><p><strong>示例：</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 日服（默认）</span></span>
<span class="line"><span>rk</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 台服</span></span>
<span class="line"><span>twrk</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 国服</span></span>
<span class="line"><span>cnrk</span></span></code></pre></div><hr><div class="nav-footer"><a href="/help/other/status" class="nav-prev">← 上一章：其他功能</a><a href="./user-data" class="nav-next">开始：用户数据管理 →</a></div>`,23)])])}const k=e(s,[["render",i]]);export{b as __pageData,k as default};
